const FALLBACK_TITLE = 'Eli JKT48 Moment';
const FALLBACK_DESCRIPTION = 'Eli JKT48 Theater Performance';

const normalizeText = (value) => (typeof value === 'string' ? value.trim() : '');

const getSequenceFromId = (id) => {
  const match = normalizeText(id).match(/(\d+)\s*$/);
  return match ? match[1] : '';
};

const buildTitle = (img) => {
  const currentTitle = normalizeText(img.title);
  if (currentTitle && currentTitle !== FALLBACK_TITLE) return currentTitle;

  const seq = getSequenceFromId(img.id);
  const suffix = seq ? ` #${seq}` : '';
  return `Eli JKT48 - ${img.month} ${img.year}${suffix}`;
};

const buildDescription = (img) => {
  const currentDescription = normalizeText(img.description);
  if (currentDescription && currentDescription !== FALLBACK_DESCRIPTION) return currentDescription;
  return `Captured at ${img.location} on ${img.date}.`;
};

const buildAlt = (img, title) => {
  const base = `${title} at ${img.location}, ${img.month} ${img.year}`;
  return base.replace(/\s+/g, ' ').trim();
};

const buildOptimized = (url, thumbnail) => {
  const base = normalizeText(url).replace(/\.[^./]+$/, '');
  if (!base) return {};
  return {
    thumbnail: normalizeText(thumbnail) || url,
    webpSrcSet: `${base}.webp 1x`,
    avifSrcSet: `${base}.avif 1x`,
  };
};

export const GALLERY_IMAGES = RAW_DATA.map((img) => {
  const title = buildTitle(img);
  const description = buildDescription(img);
  const optimized = buildOptimized(img.url, img.thumbnail);

  return {
    ...img,
    title,
    description,
    alt: buildAlt(img, title),
    thumbnail: optimized.thumbnail,
    optimized,
    era: img.year, // Map year to era for the context filter
  };
});

// Dynamically compute available eras from the data
export const getAvailableEras = () => {
  const years = [...new Set(RAW_DATA.map(img => img.year))].sort((a, b) => b - a);
  return years.map(year => ({
    id: year,
    label: `${year} Archive`,
  }));
};

export const getFeaturedImages = () => GALLERY_IMAGES.filter(img => img.featured);
export const getImageById = (id) => GALLERY_IMAGES.find(img => img.id === id);
